-- 광명시 자치법규 시드 데이터
-- 총 91개 조문

INSERT OR IGNORE INTO regulations (law_name, article, content) VALUES
  ('광명시 공유경제 활성화에 관한 조례', '제1조(목적)', '제1조(목적) 이조례는공유경제활성화를통해지역자원의효율적활용과구 성원간의적극적인나눔등으로주민간의소통과화합, 지역경제를활성화하 기위해필요한사항을규정함을목적으로한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의뜻은다음과같다. 1. “공유경제”란공간, 물건, 재능, 경험등자원을함께사용함으로써주민의 편의를증진하고, 사회적경제적환경적가치를창출하는경제활동을말한 다. 2. “공유단체”란공유경제를통해복지, 문화, 환경, 교통등사회문제해결에 기여하고자하는단체로서제9조에따라지정된단체를말한다. 3. “공유기업”이란공유경제를통해복지, 문화, 환경, 교통, 등사회문제해결 에기여하고자하는기업으로서제9조에따라지정된기업을말한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제3조(시장등의책무)', '제3조(시장등의책무) ①광명시장(이하“시장”이라한다)은공유경제활성화 를위하여필요한제도와여건을조성하고이를위한시책을마련하여야한 다. ②시장및「지방공기업법」에따라광명시(이하“시”라한다)가설립한공 사의장, 출자출연기관의장등은공공자원이공유경제에활용될수있도록 노력하여야한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제4조(시민등의참여)', '제4조(시민등의참여) 시민과기업은공유경제영역의발굴및공유경제실천 을주도하고공유경제활성화에적극참여한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제5조(다른조례와의관계)', '제5조(다른조례와의관계) 공유경제활성화에관하여다른조례에특별한규 정이있는경우를제외하고는이조례에서정하는바에따른다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제6조(공유경제활성화정책)', '제6조(공유경제활성화정책) 시장은공유경제활성화를위하여다음각호의 정책을적극추진하여야한다. 1. 공유경제활성화를위한법규및제도개선 2. 지역특성에맞는공유경제영역의발굴및보급 3. 공유단체및공유기업육성지원 4. 공유경제활성화를위한인식확산 5. 그밖에공유경제활성화를위하여필요한정책'),
  ('광명시 공유경제 활성화에 관한 조례', '제7조(기본계획의수립시행)', '제7조(기본계획의수립시행) ①시장은공유경제활성화를위한기본계획(이 하“기본계획” 이라한다)을5년마다수립시행하여야한다. ②기본계획에는다음각호의사항이포함되어야한다. 1. 공유경제활성화목표와방향 2. 공유경제활성화시책개발및홍보 3. 공유경제활성화를위한재원조달에관한사항 4. 공유경제활성화를위한제도개선에관한사항 5. 그밖에공유경제활성화에필요한사항 ③시장은기본계획을수립시행하기위하여필요한경우에는공유경제와관 련한기관또는단체등에의견의진술이나자료제출에대한협조를요청할 수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제8조(실태조사)', '제8조(실태조사) ①시장은공유경제에대한효율적정책수립을위하여공유 경제활성화에대한실태조사를할수있다. ②시장은제1항의실태조사를공유경제에관련된기관또는단체등에위탁 하여실시할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제9조(공유기업및공유단체의지정등)', '제9조(공유기업및공유단체의지정등) ①시장은공유경제활동을통해사회 적문제를해결하고자하는다음각호의어느하나에해당하는법인및기 업, 단체를공유기업및공유단체로지정할수있다. 1. 「민법」에따른비영리법인 2. 「상법」에따른회사 3. 「사회적기업육성법」에따른사회적기업및중앙부처또는경기도에서 사회적기업으로육성하기위하여지정한예비사회적기업 4. 「협동조합기본법」에따른협동조합및사회적협동조합 5. 「도시재생활성화및지원에관한특별법」제2조제1항제9호에따른마을 기업으로행정안전부또는경기도가선정한기업 6. 「비영리민간단체지원법」에따른비영리민간단체 7. 그밖에공유경제활성화를위하여필요하다고시장이인정하는법인및 기업, 단체 ②제1항에따른공유기업및단체의지정의요건, 절차와취소등에필요한 사항은시장이따로정한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제10조(공유경제정보관리시스템구축운영)', '제10조(공유경제정보관리시스템구축운영) 시장은공유경제활성화를위하여 공유경제정보관리시스템을구축운영할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제11조(공유경제활동지원등)', '제11조(공유경제활동지원등) 시장은공유경제활성화를위한사업을수행 하는관련기관이나단체에예산의범위에서그사업에따른소요경비의일 부또는전부를지원할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제12조(지정전단체또는기업지원)', '제12조(지정전단체또는기업지원) 시장은공유경제활성화를위해필요하 다고인정하는경우공유경제사업을운영하는기업또는단체에게공유기업 또는공유단체의지정전이라도홍보지원, 컨설팅등을지원할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제13조(지원신청등)', '제13조(지원신청등) ①공유사업을추진하는데필요한지원을받고자하는 경우에는사업계획을수립하여시장에게서면으로지원신청을하여야한다. ②지원받는기관이나단체는사업계획서에따라수행해야하며, 시장은사업 이원활히수행되고있는지수시로확인점검하여야한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제14조(교육및홍보등)', '제14조(교육및홍보등) ①시장은공유경제활성화를위하여관련기관이나 단체등에대하여교육을실시할수있다. ②시장은공유경제인식확산을위하여공유경제에대한홍보등을할수 있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제15조(포상)', '제15조(포상) 시장은공유경제활성화에기여한공적이탁월한단체·기관또는 사람에게「광명시포상조례」에따라포상할수있으며, 광명시본청직속 기관사업소의부서및하부행정기관에게는예산의범위에서포상금을지급 할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제16조(공유경제위원회)', '제16조(공유경제위원회) ➀시장은공유경제활성화를위해다음각호의사항 을심의하기위하여광명시공유경제위원회(이하“위원회”라한다)를둘수 있다. 1. 기본계획및시책수립시행에관한사항 2. 공유기업및단체지정및지정취소에관한사항 3. 공유기업및단체지원에관한사항 4. 그밖에공유경제활성화를위하여필요하다고시장이판단한사항 ②제1항에따른위원회업무는「광명시사회적기업육성및지원에관한 조례」제4조에따른광명시사회적기업육성위원회에서대행한다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제1조(목적)', '제1조(목적) 이규칙은「광명시공유경제활성화에관한조례」의시행에필 요한사항을규정함을목적으로한다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제2조(사회적문제범위)', '제2조(사회적문제범위) 「광명시공유경제활성화에관한조례」(이하“조 례”라한다)제9조제1항에따른“사회적문제”란다음각호의어느하나에해 당하는것을말한다. 1. 경기침체, 청년취업, 조기은퇴등경제및일자리관련문제 2. 장애인, 고령화, 청년주거, 공동체해체, 1인가구증가등복지관련문제 3. 문화소외, 문화프로그램및관광숙박시설부족등문화관련문제 4. 과잉소비, 에너지고갈, 자원낭비등환경관련문제 5. 교통체증, 주차시설부족, 교통약자이동불편등교통관련문제 6. 교육격차, 교육기회불평등, 교육시설부족등교육관련문제 7. 그밖에광명시공유경제위원회(이하“위원회”라한다)에서인정하는사항'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제3조(공유기업및공유단체지정요건)', '제3조(공유기업및공유단체지정요건) ①조례제9조제1항에따라공유기업 및공유단체로지정받으려는자는다음각호의요건을갖추어야한다. 1. 공유를통한사회적문제해결추구 2. 최근6개월이상공유활동또는공유사업실적보유 ②제1항제2호의경우위원회에서공유경제활성화를위해필요하다고결정 한때에는달리정할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제4조(지정절차)', '제4조(지정절차) ①제3조에따라공유기업및공유단체로지정받으려는자는 별지제1호서식의신청서와지정심사에필요한다음각호의서류를첨부하 여광명시장(이하“시장”이라한다)에게제출하여야한다. 1. 공유경제활성화와관련된사업계획서 2. 제3조제1항에따른요건을갖추고있음을확인할수있는서류 3. 그밖에위원회가공유기업및공유단체지정을위한심사에필요하다고 인정하여요구하는자료등 ②시장은제1항에따라지정신청서를접수한때에는신청기간종료일로부 터60일이내에위원회의심의를거친후, 공유기업또는공유단체로적합하 다고인정하는경우에는신청인에게별지제2호서식공유기업또는공유단 체지정서를발급하여야한다. ③공유기업및공유단체의지정기간은3년으로하되, 재심사를통해연장할 수있다. ④지정기간을연장받고자하는자는지정기간종료3개월전에별지제3호 서식의재지정신청서를시장에게제출하여야한다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제5조(지정취소및철회)', '제5조(지정취소및철회) ①시장은공유기업및공유단체로지정받은자가다 음각호의어느하나에해당하는경우에는지정을취소하거나철회할수있 다. 1. 거짓또는부정한방법으로지정을받은경우 2. 지정요건을갖추지못하게된경우 3. 위법또는부당한활동으로참여시민에게피해를입힌경우 4. 지정후연속6개월간공유활동및사업실적이없거나현저히적을경 우 5. 지정을유지시키거나계속지정할실익이없는것으로위원회에서인정 하는경우 ②시장은지정을취소또는철회하고자할때는행정절차법제2조제5호의 청문과위원회의심의를거친후, 취소또는철회사유를밝혀해당공유기업 또는공유단체의대표자에게알려야한다. ③시장은보조금을지원받은공유기업또는공유단체가제1항에따라지정 이취소된경우에는지원된보조금전액을환수할수있으며, 지정이철회된 경우에는보조금집행잔액을환수할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제6조(지정종료)', '제6조(지정종료) 공유기업또는공유단체로지정받은자가다음각호의어느 하나에해당되는경우그지정을종료하여야한다. 1. 지정기간이종료된경우 2. 지정서를자진반납하는경우 3. 폐업, 도산등으로기업또는단체를운영하지않는것이확인된경우'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제7조(지정변경)', '제7조(지정변경) ①공유기업또는공유단체가당초지정내용을변경할때별 지제4호서식의지정변경신청서를시장에게제출하여야한다. ②시장은제1항에따라지정변경신청서를제출한공유기업또는공유단체 에대하여변경내용이적합하다고인정한경우지정을변경할수있다. ③제2항의지정변경시사업목적, 사업내용, 사업범위등중요한사항에대 한지정변경은위원회의심의를거쳐야한다. ④시장은지정이변경된경우신청인에게변경된지정서를발급하여야한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제1조(목적)', '제1조(목적) 이조례는광명시가공정무역을지원·육성하고시민들의윤리적 소비인식증진과활동을장려하는데필요한사항을규정함을목적으로한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의정의는다음각호와같다. 1. “공정무역(Fair Trade)”이란대화와투명성, 존중에기초하여국제무역에서 보다공평하고정의로운관계를추구하는거래기반의동반자관계로서, 특히저개발국가에서경제발전의혜택으로부터소외된생산자와노동자에 게더나은거래조건을제공하고그들의권리를보호함으로써지속가능 한발전에기여하는것을목적으로하는무역을말한다. 2. “공정무역단체(Fair Trade Organization)”란국제공정무역기구인증제품 을취급하거나공정무역을올바르게알리고실천하기위한다양한활동을 수행하는국내외조직을말한다. 3. “공정무역제품“이란국제공정무역인증기구에서FAIRTRADE 마크로인증 한제품및공정무역단체가개발하거나유통하는제품을말한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제3조(기본원칙)', '제3조(기본원칙) 공정무역지원및육성은다음각호의기본원칙에따라추진 한다. 1. 공정무역이해관계자상호간의신뢰와존중을제고할수있는사회시스 템구축을목표로한다. 2. 공정무역운동활성화를위해시민의자발적참여를장려하고스스로주도 할수있는기반마련에힘쓴다. 3. 공정무역운동은시민과행정기관의상호신뢰와협력을통해추진한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제4조(시장의책무)', '제4조(시장의책무) 광명시장(이하“시장”이라한다)은시민이중심이되는공 정무역사업을적극지원하여야하며공정무역사업활성화정책을지속적으 로추진하여야한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제5조(다른법령및조례와의관계)', '제5조(다른법령및조례와의관계) 공정무역지원및육성에관한다른법령 또는조례에특별한규정이있는경우를제외하고는이조례가정하는바에 따른다. 제2장공정무역활성화지원'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제6조(공정무역활성화추진계획)', '제6조(공정무역활성화추진계획) ①시장은광명시공정무역사업활성화추 진계획(이하“추진계획”이라한다)을수립·시행하여야한다. ②제1항의추진계획에는다음각호의사항이포함되어야한다. 1. 공정무역주요사업계획및추진방향 2. 공정무역위원회등민·관협력체계구성및운영 3. 공정무역의활성화를위한교육·홍보·지원에관한사항 4. 공정무역제품판로개척및구매확산에관한사항 5. 그밖에공정무역활성화에필요하다고인정되는사항'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제7조(공정무역도시조성및인증)', '제7조(공정무역도시조성및인증) 시장은공정무역도시조성및인증을위한 사업을추진하여야하며, 공정무역도시조성업무의효율성및책임성을증 진하기위하여공정무역담당부서를설치할수있다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제8조(지원범위)', '제8조(지원범위) 시장은다음각호에해당하는공정무역사업에대하여행정 적·재정적지원을할수있다. 1. 공정무역제품공공구매활성화사업 2. 공정무역판로마케팅사업 3. 공정무역저변확대를위한교육, 홍보, 캠페인사업 4. 지역농산물과공정무역을연계하는상품개발사업 5. 공정무역발전을위한국내·외교류사업 6. 공정무역도시조성및인증기준달성을위한사업 7. 그밖에공정무역사업추진을위해필요하다고시장및공정무역위원회 가인정한사업 제3장위원회'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제9조(위원회구성등)', '제9조(위원회구성등) ①시장은공정무역사업에대한시장의자문에응하기 위하여공정무역위원회(이하“위원회”라한다)를구성할수있다. ②위원회는공동위원장2명과부위원장1명을포함하여10명이내로구성한다. ③공동위원장은부시장과위촉직위원중에서선출하는1명이되며, 부위원 장은위원중에서선출한다. ④위원은다음각호의어느하나에해당하는사람중에서시장이위촉하며, 공정무역업무담당실·국장은당연직위원이된다. 단, 위촉직의경우특정성 별이10분의6을초과하지않도록한다.〈개정2022. 8. 2〉 1. 공정무역관련전문가로학식과경험이풍부한자 2. 지역사회에서공정무역활동에적극적으로참여하고역량이높은자 3. 시의회에서추천한의원 4. 그밖에시장이필요하다고인정한사람 ⑤공무원인위원의임기는그직에재직하고있는기간으로하고, 그외위 원의임기는위촉일로부터2년으로하며, 한차례만연임할수있다. 다만, 보 궐위원의임기는전임위원의잔여임기로한다. ⑥위원회의사무처리를위하여간사1명을두되, 간사는공정무역업무를 담당하는부서의장이된다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제10조(위원회의기능)', '제10조(위원회의기능) 위원회는다음각호의사항을자문또는심의한다. 1. 공정무역주요사업수립및평가와관련한사항 2. 공정무역지원단체의선정및지원에관한사항 3. 공정무역활동을위한홍보및교육·훈련등에관한사항 4. 그밖에공정무역사업추진을위해시장이필요하다고인정하는사항'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제11조(위원회의운영)', '제11조(위원회의운영) ①위원회의회의는다음각호의어느하나에해당하 는경우에소집한다. 다만, 부득이한사유로위원회소집이어려운경우에는 서면심의를할수있다. 1. 시장의소집요구가있을때 2. 재적위원3분의1이상의소집요구가있을때 3. 그밖에위원장이필요하다고인정하는때 ②회의는재적위원과반수의출석으로개의하고, 출석위원과반수의찬성으 로의결한다. ③위원장이부득이한사유로인하여직무를수행할수없을때에는부위원 장이그직무를수행한다. ④위원회는심의또는자문을위하여관계공무원또는관련전문가를회의 에참석하게하여의견을듣거나관계기관·단체등에자료또는의견제출 등협조를요청할수있다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제12조(위원의해촉)', '제12조(위원의해촉) 시장은위원이다음각호의어느하나에해당하는사유 가있는경우에는해촉할수있다. 1. 질병이나그밖의사유로임무를수행하기어려운경우 2. 위원스스로사퇴를원하는경우 3. 그밖에해촉할만한사유가발생한경우'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제13조(위원의제척등)', '제13조(위원의제척등) ①위원이심의대상과관련하여직·간접으로이해관 계가있다고인정되는경우에는해당안건의심의에서제척된다. ②위원이제1항의사유에해당하는경우에는스스로해당안건의심의·의결 에서회피하여야한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제14조(수당등)', '제14조(수당등) ①위원회에참석한공무원이아닌위원및전문가등에대 하여는예산의범위에서「광명시각종위원회설치및운영조례」에따라 수당및여비를지급할수있다. ②위원회위원및민간전문가등의심사와전문지식이요구되는자문에는 「지방자치단체세출예산집행기준」에따른심사수당과자문료를지급할수 있다. 제4장공정무역제품판로확대'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제15조(공정무역제품구매촉진등)', '제15조(공정무역제품구매촉진등) ①시장은「지방자치단체를당사자로하는 계약에관한법률」및「광명시재무회계규칙」등관련규정에서허용하는 범위에서공정무역제품을우선구매할수있다. ②시장은관내에소재한시청, 시의회, 공사, 재단등의공공기관및유관단 체등에공정무역제품의우선구매를권고할수있다. ③시장은공정무역제품의생산과구매촉진에필요한관련정보를수집하여 관내기업, 민간기관및단체, 공공기관등에제공할수있다. ④시장은공공기관또는민간단체등이공정무역제품의소비촉진을위하여 추진하는교육·홍보사업에대하여필요한경비의일부를지원하거나행정지 원을할수있다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제16조(공정무역판매처표시의제정)', '제16조(공정무역판매처표시의제정) ①시장은관내공정무역제품의유통 활성화를위하여공정무역제품취급매장및판매처를나타내는표시(이하 “판매처표시”라한다)를제정할수있다. ②판매처표시는위원회의심의를거쳐확정한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제17조(공정무역판매처표시의사용등)', '제17조(공정무역판매처표시의사용등) ①판매처표시는시장이정하는공 정무역제품취급매장및판매처등에사용할수있다. ②판매처표시를사용하고자하는기관, 단체및사업자등은시장에게사용 승인신청서를제출하고, 위원회의심의를거쳐사용권에대한승인을받아야 한다. ③판매처표시를사용하는사용자가사회적으로민원을야기하거나공정무 역정신에위반된행위를할경우시장은위원회의심의를거쳐즉시사용승 인을취소할수있다. 제5장보칙'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제18조(준용)', '제18조(준용) 이조례에규정된사항외에공정무역단체의지원및관리등에 필요한사항은「광명시지방보조금관리조례」등예산·회계관계법령등을 준용한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제19조(시행규칙)', '제19조(시행규칙) 이조례의시행에필요한사항은규칙으로정한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제1조(목적)', '제1조(목적) 이조례는「사회적기업육성법」에따른사회적기업과예비사회적기업의 육성및지원을통하여사회서비스를확충하고, 새로운일자리를창출함으로써지역 사회의통합과주민의삶의질향상에기여함을목적으로한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의정의는다음과같다. 1. “사회적기업”이란「사회적기업육성법」(이하“법”이라한다) 제2조제1호의기업 을말한다. 2. “예비사회적기업”이란제1호의사회적기업으로인증받지는않았으나사회서비스 의제공, 취약계층에게일자리제공등사회적기업으로서의실체를갖추고장차 사회적기업으로의전환을준비하는기업을말한다. 3. “취약계층”이란법제2조제2호의계층을말한다. 4. “사회서비스”란법제2조제3호의서비스를말한다. 5. “연계기업”이란법제2조제4호의기업을말한다. 6. “사회적기업등”이란사회적기업및예비사회적기업을말한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제3조(사회적기업육성계획의수립)', '제3조(사회적기업육성계획의수립) ①광명시장(이하“시장”이라한다)은사회서비스 확충및일자리창출을위하여광명시사회적기업육성계획(이하“육성계획”이라한 다)을수립ㆍ시행하여야한다. ②제1항의육성계획에는다음각호의사항이포함되어야한다. 1. 사회적기업등의육성및지원을위한추진방향 2. 사회적기업등의활성화를위한여건조성에관한사항 3. 사회적기업등의운영지원에관한사항 4. 그밖에사회적기업등의육성및지원을위하여시장이필요하다고인정하는사항 ③시장은육성계획추진을위하여매년시행계획을수립ㆍ시행하되, 육성계획및 연도별시행계획기간이종료된후에는해당계획의성과등에대하여평가를실시 한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제4조(사회적기업육성위원회설치)', '제4조(사회적기업육성위원회설치) 시장은사회적기업등의육성및지원에관한다 음각호의사항을심의하기위하여광명시사회적기업육성위원회(이하“위원회”라 한다)를둔다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제5조(위원회기능)', '제5조(위원회기능) 위원회는다음각호의사항을심의한다. 1. 사회적기업등의육성계획및연도별시행계획의수립ㆍ평가에관한사항 2. 사회적기업등의운영과지원에관한사항 3. 예비사회적기업의운영과지원에관한사항 4. 그밖에사회적기업등의육성과지원을위하여시장이필요하다고인정하는사항'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제6조(위원회구성)', '제6조(위원회구성) ①위원회는위원장1명을포함한15명이내의위원으로구성하 되위원장은부시장이되며, 부위원장은위원중에서호선한다. ②위원은다음각호의사람중에서시장이임명또는위촉한다. 1. 당연직위원은광명시관계공무원으로한다. 2. 위촉직위원은광명시의회에서추천하는의원2명이내, 사회적기업등에대하여 학식과경험이풍부한사람, 시민단체및기업관계자등으로한다. ③위촉직위원의임기는2년으로한다. 다만, 공무원인위원의임기는해당직위에 재직하는기간으로한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제7조(위원장의직무)', '제7조(위원장의직무) ①위원장은위원회를대표하고, 위원회의직무를총괄한다. ②부위원장은위원장을보좌하며, 위원장이부득이한사유로직무를수행할수없 는경우에는그직무를대행한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제8조(회의)', '제8조(회의) ①위원장은위원회의회의를소집하고그의장이된다. ②위원회회의는재적위원과반수의출석으로회의를시작하고, 출석위원과반수의 찬성으로의결한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제9조(간사)', '제9조(간사) 위원회의사무를처리하기위하여위원회에간사1명을두되, 간사는사 회적기업육성업무를담당하는과장이된다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제10조(수당)', '제10조(수당) 위원회에출석한위원에게는예산의범위에서수당을지급할수있다. 다만, 시소속공무원인위원이그소관업무와관련하여출석하는경우에는그러하 지아니하다.〈개정2018. 7. 31〉'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제11조(위원의해촉)', '제11조(위원의해촉) 시장은위원이다음각호의어느하나에해당하는사유가발생 하였을때에는임기만료전이라도위원을해촉한다. 1. 위원본인이사직을원할때 2. 위원이사망, 질병그밖의사유로직무를수행하기어려운때 3. 위원이장기불참등으로직무수행이부적당하다고판단된때 4. 위원이위원회활동중에비리등부패에연루되었을때'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제12조(예비사회적기업의발굴및지원)', '제12조(예비사회적기업의발굴및지원) ①시장은예비사회적기업을사회적기업으로 육성하기위해노력하여야한다. ②시장은예비사회적기업설립및사회적기업전환을촉진하기위하여관계규정에 따라사회적기업으로인증받을수있도록행정적․재정적으로지원할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제13조(사회적기업등의발굴ㆍ지원)', '제13조(사회적기업등의발굴ㆍ지원) 시장은사회서비스를제공하거나취약계층에일 자리를제공하는법인또는단체등이사회적기업등으로설립ㆍ육성될수있도록 노력하여야한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제14조(경영지원등)', '제14조(경영지원등) ①시장은사회적기업등의설립과운영에필요한경영ㆍ법률ㆍ 기술ㆍ세무ㆍ노무ㆍ회계등의분야에대한전문적인자문및정보제공등각종지 원을할수있다. ②시장은제1항의지원업무를효율적으로추진하기위하여위원회의심의를거쳐 광명시출연기관이나민간단체에위탁할수있으며, 이경우에경비의전부또는일 부를예산의범위에서지원할수있다. ③시장은사회적기업등의설립ㆍ운영에필요한전문인력의육성, 사회적기업근로 자의능력향상을위하여교육훈련을실시할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제15조(사회적기업지원센터설치)', '제15조(사회적기업지원센터설치) ①시장은제14조에따라사회적기업등의설립과 운영에필요한지원업무를체계적이고종합적으로추진하기위하여사회적기업지 원센터(이하“지원센터”라한다)를설치ㆍ운영(위탁을포함한다)할수있다. ②제1항에따라지원센터의운영을위탁하는경우그위탁기간은3년이내로하며, 그기간을연장할수있다. ③제2항에따라위탁운영기간연장신청을할때에는운영기간만료60일전까지시 장에게신청하여야한다. ④시장은제3항에따라위탁운영기간연장신청을접수받은때에는위원회의심의를 거쳐위탁기간만료30일전까지신청인에게그결과를통지하여야한다. ⑤그밖에이조례에서정하지아니한지원센터의설치및운영에관한사항은시 장이정한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제16조(시설비등의지원)', '제16조(시설비등의지원) ①시장은사회적기업등의설립또는운영에필요한부지구 입비ㆍ시설비등을지원ㆍ융자하거나국․공유지를임대할수있다. ②시장은불용물품등을사회적기업등에무상양여할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제17조(재정지원)', '제17조(재정지원) ①시장은사회적기업등의자립을위하여필요하다고인정될때에 는예산의범위에서재정지원을할수있다. ②제1항의재정지원은지원계획을공고하고위원회에서심사를통하여결정한다. ③제1항의재정지원절차및구비서류, 사업실적보고, 지원의취소및환수절차등 은규칙으로정한다. ④제2항에의하여지원계획이결정된이후사업계획이변경되는경우에도시장의 승인을받아야하며, 국가또는기관․단체등으로부터신규또는추가로재정지원을 받을경우에는보조금을조정할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제17조의2(사회적기업의책무)', '제17조의2(사회적기업의책무) 광명시의행정적, 재정적지원을받은사회적기업은 지역사회에다양한방식으로균형발전과주민복지증진을위해노력하여야한다. 〔본조신설2025. 10. 2〕'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제18조(보고및검사등)', '제18조(보고및검사등) ①재정지원을교부받은사회적기업등은「광명시지방보 조금관리조례」및관련법령에따라실적보고서및정산서등을시장에게제출하 여야한다.〈개정2016. 9. 26〉 ②시장은지원금에대한적정한집행을기하기위하여필요하다고인정될때에는 교부받은사회적기업등에대하여소속공무원에게장부․서류또는그사업내용을 검사하게할수있다. ③시장은제2항에따라보고사항의검토및지도ㆍ 감독의결과필요한경우에는 시정을명령할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제19조(우선구매의촉진)', '제19조(우선구매의촉진) ①시장은사회적기업등이생산하는재화나서비스의우선 구매촉진을위하여노력하여야한다. ②시장은민간의소비장려등사회적기업등이생산하는재화나서비스의판로개 척을지원할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제20조(조세감면)', '제20조(조세감면) 시장은사회적기업등에대하여「지방세법」및「광명시시세감 면조례」가정하는바에따라시세를감면할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제21조(연계사업)', '제21조(연계사업) ①시장은사회서비스확충및일자리창출사업을일반기업(연계 기업)과상호협약에의거공동으로추진할수있다. ②시장은다양하고많은기업이연계기업으로참여할수있도록적극노력하여야 한다. ③제1항의사회적기업에대하여는예산의범위에서행정적․재정적으로지원할수 있다.〈개정2018. 7. 31〉'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제22조(민간기업등의참여확충)', '제22조(민간기업등의참여확충) 시장은지역내민간기업ㆍ단체등이사회적기업 등의설립및육성에참여할수있도록다음각호에대하여노력하여야한다. 1. 지역내민간기업․단체간교류․협력네트워크의구축․운영지원 2. 연계기업의활성화를위한참여기업지원확대 3. 사회적기업등의설립및지원을위한기금등의설립'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제23조(홍보등)', '제23조(홍보등) 시장은사회적기업등에대한지역주민의이해증진을위하여다음 각호의조치를마련할수있다. 1. 지역내모범사회적기업모델발굴및확산지원 2. 지역내사회적기업등의제품및서비스품질제고및홍보지원 3. 전문가포럼, 워크숍개최, 사회적기업의날행사등을통한사회적기업등에대한 인식확산'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제24조(시행규칙)', '제24조(시행규칙) 이조례의시행에관하여필요한사항은규칙으로정한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제1조(시행일)', '제1조(시행일) 이조례는공포한날부터시행한다. 제2조생략'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제1조(목적)', '제1조(목적) 이조례는「교육기본법」제4조및제10조, 「평생교육법」제5 조, 제7조, 제16조및제39조에따라, 민주주의가치실현을위한학습자중심 의문해교육을지향하며, 교육의기본원칙과광명시장의책무및재정적지원 등에필요한사항을정함을목적으로한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의뜻은다음과같다. 1. “문해교육(文解敎育)”이란일상생활에필요한능력을함양하지못하여비문 해자가된성인에대하여가정, 사회및직업생활에서적극적이고주체적인 삶을영위할수있도록이루어지는조직화된교육프로그램을말한다. 2. “문해교육기관등”이란문해교육을지속적으로제공하는평생교육시설과 그에준하는기관및비영리단체를말한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제3조(기본원칙)', '제3조(기본원칙) 문해교육지원과관련된기본원칙은다음과같다. 1. 문해교육은시민의삶의질향상과사회·문화적기초생활능력을보장하기 위한교육을지향한다. 2. 문해교육대상자에게는능력에따라균등하게교육을받을권리를보장한다. 3. 문해교육대상자의기본적인권을존중하고이를보장한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제4조(대상)', '제4조(대상) 문해교육은학령기동안빈곤, 건강, 성차별등의문제로인해교 육을받지못한문해능력이필요한성인을대상으로하되, 국적을불문한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제5조(시장의책무)', '제5조(시장의책무) 광명시장(이하“시장”이라한다)은문해교육의진흥을위하 여다음각호의사항에관한시책을마련하여야한다. 1. 문해교육대상자실태조사실시 2. 문해교육종합계획수립 3. 문해교육과정및교육내용의연구개발과보급지원 4. 문해교육기관등의지원및육성 5. 문해교육관련네트워크운영및지원 3750 - 2 6. 그밖의문해교육진흥에필요한사항'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제6조(사업의공동추진)', '제6조(사업의공동추진) 시장은문해교육사업의원활한추진을위하여광명교 육지원청및문해교육기관등과협력하여문해교육에필요한공동사업을적 극추진하여야한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제7조(공공시설의이용)', '제7조(공공시설의이용) 시장이문해교육기관등으로부터공공시설의이용요 청을받은때에는그본래의용도에지장이없는범위에서특별한사유가없 는한그이용을허용하여야한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제8조(경비지원)', '제8조(경비지원) ①시장은문해교육프로그램을위하여「평생교육법」제39 조및같은법시행령제72조에따라문해교육기관등의사업에필요한경비 를예산의범위에서우선지원할수있다. ②시장은문해교육사업의예산편성에앞서광명교육지원청등문해교육 관계기관과협의할수있다. ③보조금의교부및관리에관한제반사항은「광명시지방보조금관리조 례」를따른다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제9조(교사연수등지원)', '제9조(교사연수등지원) 시장은문해교육교사의역량강화를위한연수와교 사조직의활성화사업을위하여필요한행정․재정적지원을할수있다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제10조(시행규칙)', '제10조(시행규칙) 이조례의시행에필요한사항은규칙으로정한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제1조(목적)', '제1조(목적) 이 조례는 광명시 신중년층의 인생이모작 지원에 필요한 사항을 규정함 으로써 시민의 안정된 노후생활을 통한 사회안전망 구축을 목적으로 한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제2조(정의)', '제2조(정의) 이 조례에서 사용하는 용어의 뜻은 다음과 같다.〈개정 2023. 11. 10〉 1. “신중년층”이란 50세 이상 65세 미만인 사람을 말한다. 2. “인생이모작”이란 은퇴 전후에 새로운 인생을 준비하고 성공적인 노후생활을 위 한 모든 활동을 말한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제3조(시장의책무)', '제3조(시장의책무) 광명시장(이하 “시장”이라 한다)은 신중년층의 인생이모작 지원을 위하여 필요한 정책을 수립하여 시행하여야 한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제4조(지원대상)', '제4조(지원대상) ① 인생이모작 지원사업의 지원대상은 광명시에 주소를 두고 거주하 는 신중년층으로 한다. ② 시장이 필요하다고 인정하는 경우에는 지원대상을 신중년층 이외로 확대할 수 있 다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제5조(지원사업)', '제5조(지원사업) 시장은 신중년층의 인생이모작 지원을 위하여 다음 각 호에 해당하 는 사업을 추진 할 수 있다. 1. 교육관련 사업 2. 취업지원 및 일자리지원 사업 3. 창업 역량강화 및 협업교류지원 사업 4. 사회공헌활동 통합지원 사업 5. 건강증진 및 문화·여가지원 사업 6. 그 밖에 지원이 필요하다고 시장이 인정하는 사업'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제6조(인생이모작지원시설설치·운영)', '제6조(인생이모작지원시설설치·운영) ① 시장은 제5조의 지원 사업을 체계적으로 추 진하기 위하여 광명시 신중년층 인생이모작 지원시설(이하 “시설”이라 한다)을 설치· 운영할 수 있다.〈개정 2025. 7. 4〉 ② 제1항에 따른 광명시 신중년층 인생이모작 지원시설의 명칭은 “광명시인생플러스 센터”(이하 “센터”라 한다)로 한다.〈신설 2025. 7. 4〉'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제7조(시설의위탁)', '제7조(시설의위탁) ① 시장은 시설의 효율적인 관리·운영을 위하여 시설의 전부 또는 일부를 신중년층을 위한 인생이모작 교육 및 관련 사업을 추진하는 비영리법인 등에 위탁할 수 있다. ② 제1항에 따라 시설을 위탁하는 경우 위탁의 절차 및 방법 등 위탁에 필요한 사항 은 이 조례에 규정된 사항을 제외하고 「광명시 사무의 민간위탁 촉진 및 관리 조 례」를 준용한다. ③ 시장은 수탁기관에 위탁한 사업수행에 필요한 경비의 전부 또는 일부를 예산의 범위에서 지원할 수 있다. ④ 위탁받은 시설의 장은 매 회계연도마다 사업계획 및 예산서를 작성하여 시장에게 제출하여야 하며, 세입·세출 결산보고서는 다음 회계연도 1월 31일까지 시장에게 제 출하여야 한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제8조(광명시인생이모작운영위원회설치)', '제8조(광명시인생이모작운영위원회설치) 시장은 다음 각 호의 사항을 자문하기 위 하여 광명시 인생이모작 운영위원회(이하 “위원회”라 한다)를 설치할 수 있다. 1. 신중년층 지원 시행계획의 수립에 관한 사항 2. 신중년층 지원 정책의 조정 및 평가에 관한 사항 3. 그 밖에 시장이 필요하다고 인정하는 사항 4. 위원회의 기능은 「광명시 일자리위원회 설치 및 운영에 관한 조례」에 따른 일 자리위원회에서 대행할 수 있다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제9조(수강신청)', '제9조(수강신청) 센터 교육과정을 수강하고자 하는 자는 별지 제1호서식에 따른 교육 수강 신청서를 시장에게 제출하여야 한다. 다만, 온라인으로 교육을 신청한 경우에는 신청서 제출을 생략한다. 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제10조(수강료징수)', '제10조(수강료징수) ① 시장은 센터 프로그램을 이용하는 수강생에게 수강료를 징수 할 수 있다. ② 수강료 및 수강료 면제 기준은 별표1에 따른다. 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제11조(수강료반환)', '제11조(수강료반환) ① 다음 각 호의 경우에는 즉시 반환 여부를 결정하고 이에 따 른 조치를 취하여야하며 수강료 반환 기준은 별표2에 따른다. 1. 센터의 사정으로 교육프로그램 진행이 불가능한 경우 2. 폐강이 결정되었을 때 3. 수강등록자가 본인의 의사로 수강을 포기한 경우 4. 그 밖에 시장이 필요하다고 인정하는 경우 ② 제1항에 따른 환불 사유의 경우 수강료 환불 신청서 별지 제2호 서식을 시장에게 제출하여야 한다. 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제12조(강사의위촉등)', '제12조(강사의위촉등) ① 교육 강사는 공개모집을 원칙으로 한다. 다만, 해당 분야 에 지원자가 없거나 교육의 특성상 필요하다고 인정할 경우에는 자격 또는 전문성이 있는 자를 지명하여 위촉할 수 있다. ② 위촉기간은 2년 이내로 한다. ③ 시장은 다음 각 호에 해당하는 강사를 해촉할 수 있다. 1. 업무 수행을 태만히 하여 교육에 중대한 지장을 초래한 자 2. 정당한 사유 없이 업무상 지시를 위반한 자 3. 강사로서의 품위를 손상한 자 4. 강의 관련 평가결과 기준점 이하의 경우 5. 수강생 모집 정원 미달로 폐강이 되는 경우 6. 센터의 사정으로 교육 프로그램을 개설ㆍ운영하지 못한 경우 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제13조(포상등)', '제13조(포상등) 시장은 센터 프로그램을 수료한 사람에게 수료증을 줄 수 있으며, 우수 수료자 및 공로가 인정되는 사람 및 단체 등에 대하여 「광명시 포상 조례」에 따라 포상할 수 있다. 〔본조신설 2025. 7. 4〕');

INSERT INTO regulations_fts (law_name, article, content) VALUES
  ('광명시 공유경제 활성화에 관한 조례', '제1조(목적)', '제1조(목적) 이조례는공유경제활성화를통해지역자원의효율적활용과구 성원간의적극적인나눔등으로주민간의소통과화합, 지역경제를활성화하 기위해필요한사항을규정함을목적으로한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의뜻은다음과같다. 1. “공유경제”란공간, 물건, 재능, 경험등자원을함께사용함으로써주민의 편의를증진하고, 사회적경제적환경적가치를창출하는경제활동을말한 다. 2. “공유단체”란공유경제를통해복지, 문화, 환경, 교통등사회문제해결에 기여하고자하는단체로서제9조에따라지정된단체를말한다. 3. “공유기업”이란공유경제를통해복지, 문화, 환경, 교통, 등사회문제해결 에기여하고자하는기업으로서제9조에따라지정된기업을말한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제3조(시장등의책무)', '제3조(시장등의책무) ①광명시장(이하“시장”이라한다)은공유경제활성화 를위하여필요한제도와여건을조성하고이를위한시책을마련하여야한 다. ②시장및「지방공기업법」에따라광명시(이하“시”라한다)가설립한공 사의장, 출자출연기관의장등은공공자원이공유경제에활용될수있도록 노력하여야한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제4조(시민등의참여)', '제4조(시민등의참여) 시민과기업은공유경제영역의발굴및공유경제실천 을주도하고공유경제활성화에적극참여한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제5조(다른조례와의관계)', '제5조(다른조례와의관계) 공유경제활성화에관하여다른조례에특별한규 정이있는경우를제외하고는이조례에서정하는바에따른다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제6조(공유경제활성화정책)', '제6조(공유경제활성화정책) 시장은공유경제활성화를위하여다음각호의 정책을적극추진하여야한다. 1. 공유경제활성화를위한법규및제도개선 2. 지역특성에맞는공유경제영역의발굴및보급 3. 공유단체및공유기업육성지원 4. 공유경제활성화를위한인식확산 5. 그밖에공유경제활성화를위하여필요한정책'),
  ('광명시 공유경제 활성화에 관한 조례', '제7조(기본계획의수립시행)', '제7조(기본계획의수립시행) ①시장은공유경제활성화를위한기본계획(이 하“기본계획” 이라한다)을5년마다수립시행하여야한다. ②기본계획에는다음각호의사항이포함되어야한다. 1. 공유경제활성화목표와방향 2. 공유경제활성화시책개발및홍보 3. 공유경제활성화를위한재원조달에관한사항 4. 공유경제활성화를위한제도개선에관한사항 5. 그밖에공유경제활성화에필요한사항 ③시장은기본계획을수립시행하기위하여필요한경우에는공유경제와관 련한기관또는단체등에의견의진술이나자료제출에대한협조를요청할 수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제8조(실태조사)', '제8조(실태조사) ①시장은공유경제에대한효율적정책수립을위하여공유 경제활성화에대한실태조사를할수있다. ②시장은제1항의실태조사를공유경제에관련된기관또는단체등에위탁 하여실시할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제9조(공유기업및공유단체의지정등)', '제9조(공유기업및공유단체의지정등) ①시장은공유경제활동을통해사회 적문제를해결하고자하는다음각호의어느하나에해당하는법인및기 업, 단체를공유기업및공유단체로지정할수있다. 1. 「민법」에따른비영리법인 2. 「상법」에따른회사 3. 「사회적기업육성법」에따른사회적기업및중앙부처또는경기도에서 사회적기업으로육성하기위하여지정한예비사회적기업 4. 「협동조합기본법」에따른협동조합및사회적협동조합 5. 「도시재생활성화및지원에관한특별법」제2조제1항제9호에따른마을 기업으로행정안전부또는경기도가선정한기업 6. 「비영리민간단체지원법」에따른비영리민간단체 7. 그밖에공유경제활성화를위하여필요하다고시장이인정하는법인및 기업, 단체 ②제1항에따른공유기업및단체의지정의요건, 절차와취소등에필요한 사항은시장이따로정한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제10조(공유경제정보관리시스템구축운영)', '제10조(공유경제정보관리시스템구축운영) 시장은공유경제활성화를위하여 공유경제정보관리시스템을구축운영할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제11조(공유경제활동지원등)', '제11조(공유경제활동지원등) 시장은공유경제활성화를위한사업을수행 하는관련기관이나단체에예산의범위에서그사업에따른소요경비의일 부또는전부를지원할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제12조(지정전단체또는기업지원)', '제12조(지정전단체또는기업지원) 시장은공유경제활성화를위해필요하 다고인정하는경우공유경제사업을운영하는기업또는단체에게공유기업 또는공유단체의지정전이라도홍보지원, 컨설팅등을지원할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제13조(지원신청등)', '제13조(지원신청등) ①공유사업을추진하는데필요한지원을받고자하는 경우에는사업계획을수립하여시장에게서면으로지원신청을하여야한다. ②지원받는기관이나단체는사업계획서에따라수행해야하며, 시장은사업 이원활히수행되고있는지수시로확인점검하여야한다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제14조(교육및홍보등)', '제14조(교육및홍보등) ①시장은공유경제활성화를위하여관련기관이나 단체등에대하여교육을실시할수있다. ②시장은공유경제인식확산을위하여공유경제에대한홍보등을할수 있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제15조(포상)', '제15조(포상) 시장은공유경제활성화에기여한공적이탁월한단체·기관또는 사람에게「광명시포상조례」에따라포상할수있으며, 광명시본청직속 기관사업소의부서및하부행정기관에게는예산의범위에서포상금을지급 할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례', '제16조(공유경제위원회)', '제16조(공유경제위원회) ➀시장은공유경제활성화를위해다음각호의사항 을심의하기위하여광명시공유경제위원회(이하“위원회”라한다)를둘수 있다. 1. 기본계획및시책수립시행에관한사항 2. 공유기업및단체지정및지정취소에관한사항 3. 공유기업및단체지원에관한사항 4. 그밖에공유경제활성화를위하여필요하다고시장이판단한사항 ②제1항에따른위원회업무는「광명시사회적기업육성및지원에관한 조례」제4조에따른광명시사회적기업육성위원회에서대행한다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제1조(목적)', '제1조(목적) 이규칙은「광명시공유경제활성화에관한조례」의시행에필 요한사항을규정함을목적으로한다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제2조(사회적문제범위)', '제2조(사회적문제범위) 「광명시공유경제활성화에관한조례」(이하“조 례”라한다)제9조제1항에따른“사회적문제”란다음각호의어느하나에해 당하는것을말한다. 1. 경기침체, 청년취업, 조기은퇴등경제및일자리관련문제 2. 장애인, 고령화, 청년주거, 공동체해체, 1인가구증가등복지관련문제 3. 문화소외, 문화프로그램및관광숙박시설부족등문화관련문제 4. 과잉소비, 에너지고갈, 자원낭비등환경관련문제 5. 교통체증, 주차시설부족, 교통약자이동불편등교통관련문제 6. 교육격차, 교육기회불평등, 교육시설부족등교육관련문제 7. 그밖에광명시공유경제위원회(이하“위원회”라한다)에서인정하는사항'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제3조(공유기업및공유단체지정요건)', '제3조(공유기업및공유단체지정요건) ①조례제9조제1항에따라공유기업 및공유단체로지정받으려는자는다음각호의요건을갖추어야한다. 1. 공유를통한사회적문제해결추구 2. 최근6개월이상공유활동또는공유사업실적보유 ②제1항제2호의경우위원회에서공유경제활성화를위해필요하다고결정 한때에는달리정할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제4조(지정절차)', '제4조(지정절차) ①제3조에따라공유기업및공유단체로지정받으려는자는 별지제1호서식의신청서와지정심사에필요한다음각호의서류를첨부하 여광명시장(이하“시장”이라한다)에게제출하여야한다. 1. 공유경제활성화와관련된사업계획서 2. 제3조제1항에따른요건을갖추고있음을확인할수있는서류 3. 그밖에위원회가공유기업및공유단체지정을위한심사에필요하다고 인정하여요구하는자료등 ②시장은제1항에따라지정신청서를접수한때에는신청기간종료일로부 터60일이내에위원회의심의를거친후, 공유기업또는공유단체로적합하 다고인정하는경우에는신청인에게별지제2호서식공유기업또는공유단 체지정서를발급하여야한다. ③공유기업및공유단체의지정기간은3년으로하되, 재심사를통해연장할 수있다. ④지정기간을연장받고자하는자는지정기간종료3개월전에별지제3호 서식의재지정신청서를시장에게제출하여야한다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제5조(지정취소및철회)', '제5조(지정취소및철회) ①시장은공유기업및공유단체로지정받은자가다 음각호의어느하나에해당하는경우에는지정을취소하거나철회할수있 다. 1. 거짓또는부정한방법으로지정을받은경우 2. 지정요건을갖추지못하게된경우 3. 위법또는부당한활동으로참여시민에게피해를입힌경우 4. 지정후연속6개월간공유활동및사업실적이없거나현저히적을경 우 5. 지정을유지시키거나계속지정할실익이없는것으로위원회에서인정 하는경우 ②시장은지정을취소또는철회하고자할때는행정절차법제2조제5호의 청문과위원회의심의를거친후, 취소또는철회사유를밝혀해당공유기업 또는공유단체의대표자에게알려야한다. ③시장은보조금을지원받은공유기업또는공유단체가제1항에따라지정 이취소된경우에는지원된보조금전액을환수할수있으며, 지정이철회된 경우에는보조금집행잔액을환수할수있다.'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제6조(지정종료)', '제6조(지정종료) 공유기업또는공유단체로지정받은자가다음각호의어느 하나에해당되는경우그지정을종료하여야한다. 1. 지정기간이종료된경우 2. 지정서를자진반납하는경우 3. 폐업, 도산등으로기업또는단체를운영하지않는것이확인된경우'),
  ('광명시 공유경제 활성화에 관한 조례 시행규칙', '제7조(지정변경)', '제7조(지정변경) ①공유기업또는공유단체가당초지정내용을변경할때별 지제4호서식의지정변경신청서를시장에게제출하여야한다. ②시장은제1항에따라지정변경신청서를제출한공유기업또는공유단체 에대하여변경내용이적합하다고인정한경우지정을변경할수있다. ③제2항의지정변경시사업목적, 사업내용, 사업범위등중요한사항에대 한지정변경은위원회의심의를거쳐야한다. ④시장은지정이변경된경우신청인에게변경된지정서를발급하여야한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제1조(목적)', '제1조(목적) 이조례는광명시가공정무역을지원·육성하고시민들의윤리적 소비인식증진과활동을장려하는데필요한사항을규정함을목적으로한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의정의는다음각호와같다. 1. “공정무역(Fair Trade)”이란대화와투명성, 존중에기초하여국제무역에서 보다공평하고정의로운관계를추구하는거래기반의동반자관계로서, 특히저개발국가에서경제발전의혜택으로부터소외된생산자와노동자에 게더나은거래조건을제공하고그들의권리를보호함으로써지속가능 한발전에기여하는것을목적으로하는무역을말한다. 2. “공정무역단체(Fair Trade Organization)”란국제공정무역기구인증제품 을취급하거나공정무역을올바르게알리고실천하기위한다양한활동을 수행하는국내외조직을말한다. 3. “공정무역제품“이란국제공정무역인증기구에서FAIRTRADE 마크로인증 한제품및공정무역단체가개발하거나유통하는제품을말한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제3조(기본원칙)', '제3조(기본원칙) 공정무역지원및육성은다음각호의기본원칙에따라추진 한다. 1. 공정무역이해관계자상호간의신뢰와존중을제고할수있는사회시스 템구축을목표로한다. 2. 공정무역운동활성화를위해시민의자발적참여를장려하고스스로주도 할수있는기반마련에힘쓴다. 3. 공정무역운동은시민과행정기관의상호신뢰와협력을통해추진한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제4조(시장의책무)', '제4조(시장의책무) 광명시장(이하“시장”이라한다)은시민이중심이되는공 정무역사업을적극지원하여야하며공정무역사업활성화정책을지속적으 로추진하여야한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제5조(다른법령및조례와의관계)', '제5조(다른법령및조례와의관계) 공정무역지원및육성에관한다른법령 또는조례에특별한규정이있는경우를제외하고는이조례가정하는바에 따른다. 제2장공정무역활성화지원'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제6조(공정무역활성화추진계획)', '제6조(공정무역활성화추진계획) ①시장은광명시공정무역사업활성화추 진계획(이하“추진계획”이라한다)을수립·시행하여야한다. ②제1항의추진계획에는다음각호의사항이포함되어야한다. 1. 공정무역주요사업계획및추진방향 2. 공정무역위원회등민·관협력체계구성및운영 3. 공정무역의활성화를위한교육·홍보·지원에관한사항 4. 공정무역제품판로개척및구매확산에관한사항 5. 그밖에공정무역활성화에필요하다고인정되는사항'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제7조(공정무역도시조성및인증)', '제7조(공정무역도시조성및인증) 시장은공정무역도시조성및인증을위한 사업을추진하여야하며, 공정무역도시조성업무의효율성및책임성을증 진하기위하여공정무역담당부서를설치할수있다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제8조(지원범위)', '제8조(지원범위) 시장은다음각호에해당하는공정무역사업에대하여행정 적·재정적지원을할수있다. 1. 공정무역제품공공구매활성화사업 2. 공정무역판로마케팅사업 3. 공정무역저변확대를위한교육, 홍보, 캠페인사업 4. 지역농산물과공정무역을연계하는상품개발사업 5. 공정무역발전을위한국내·외교류사업 6. 공정무역도시조성및인증기준달성을위한사업 7. 그밖에공정무역사업추진을위해필요하다고시장및공정무역위원회 가인정한사업 제3장위원회'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제9조(위원회구성등)', '제9조(위원회구성등) ①시장은공정무역사업에대한시장의자문에응하기 위하여공정무역위원회(이하“위원회”라한다)를구성할수있다. ②위원회는공동위원장2명과부위원장1명을포함하여10명이내로구성한다. ③공동위원장은부시장과위촉직위원중에서선출하는1명이되며, 부위원 장은위원중에서선출한다. ④위원은다음각호의어느하나에해당하는사람중에서시장이위촉하며, 공정무역업무담당실·국장은당연직위원이된다. 단, 위촉직의경우특정성 별이10분의6을초과하지않도록한다.〈개정2022. 8. 2〉 1. 공정무역관련전문가로학식과경험이풍부한자 2. 지역사회에서공정무역활동에적극적으로참여하고역량이높은자 3. 시의회에서추천한의원 4. 그밖에시장이필요하다고인정한사람 ⑤공무원인위원의임기는그직에재직하고있는기간으로하고, 그외위 원의임기는위촉일로부터2년으로하며, 한차례만연임할수있다. 다만, 보 궐위원의임기는전임위원의잔여임기로한다. ⑥위원회의사무처리를위하여간사1명을두되, 간사는공정무역업무를 담당하는부서의장이된다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제10조(위원회의기능)', '제10조(위원회의기능) 위원회는다음각호의사항을자문또는심의한다. 1. 공정무역주요사업수립및평가와관련한사항 2. 공정무역지원단체의선정및지원에관한사항 3. 공정무역활동을위한홍보및교육·훈련등에관한사항 4. 그밖에공정무역사업추진을위해시장이필요하다고인정하는사항'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제11조(위원회의운영)', '제11조(위원회의운영) ①위원회의회의는다음각호의어느하나에해당하 는경우에소집한다. 다만, 부득이한사유로위원회소집이어려운경우에는 서면심의를할수있다. 1. 시장의소집요구가있을때 2. 재적위원3분의1이상의소집요구가있을때 3. 그밖에위원장이필요하다고인정하는때 ②회의는재적위원과반수의출석으로개의하고, 출석위원과반수의찬성으 로의결한다. ③위원장이부득이한사유로인하여직무를수행할수없을때에는부위원 장이그직무를수행한다. ④위원회는심의또는자문을위하여관계공무원또는관련전문가를회의 에참석하게하여의견을듣거나관계기관·단체등에자료또는의견제출 등협조를요청할수있다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제12조(위원의해촉)', '제12조(위원의해촉) 시장은위원이다음각호의어느하나에해당하는사유 가있는경우에는해촉할수있다. 1. 질병이나그밖의사유로임무를수행하기어려운경우 2. 위원스스로사퇴를원하는경우 3. 그밖에해촉할만한사유가발생한경우'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제13조(위원의제척등)', '제13조(위원의제척등) ①위원이심의대상과관련하여직·간접으로이해관 계가있다고인정되는경우에는해당안건의심의에서제척된다. ②위원이제1항의사유에해당하는경우에는스스로해당안건의심의·의결 에서회피하여야한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제14조(수당등)', '제14조(수당등) ①위원회에참석한공무원이아닌위원및전문가등에대 하여는예산의범위에서「광명시각종위원회설치및운영조례」에따라 수당및여비를지급할수있다. ②위원회위원및민간전문가등의심사와전문지식이요구되는자문에는 「지방자치단체세출예산집행기준」에따른심사수당과자문료를지급할수 있다. 제4장공정무역제품판로확대'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제15조(공정무역제품구매촉진등)', '제15조(공정무역제품구매촉진등) ①시장은「지방자치단체를당사자로하는 계약에관한법률」및「광명시재무회계규칙」등관련규정에서허용하는 범위에서공정무역제품을우선구매할수있다. ②시장은관내에소재한시청, 시의회, 공사, 재단등의공공기관및유관단 체등에공정무역제품의우선구매를권고할수있다. ③시장은공정무역제품의생산과구매촉진에필요한관련정보를수집하여 관내기업, 민간기관및단체, 공공기관등에제공할수있다. ④시장은공공기관또는민간단체등이공정무역제품의소비촉진을위하여 추진하는교육·홍보사업에대하여필요한경비의일부를지원하거나행정지 원을할수있다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제16조(공정무역판매처표시의제정)', '제16조(공정무역판매처표시의제정) ①시장은관내공정무역제품의유통 활성화를위하여공정무역제품취급매장및판매처를나타내는표시(이하 “판매처표시”라한다)를제정할수있다. ②판매처표시는위원회의심의를거쳐확정한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제17조(공정무역판매처표시의사용등)', '제17조(공정무역판매처표시의사용등) ①판매처표시는시장이정하는공 정무역제품취급매장및판매처등에사용할수있다. ②판매처표시를사용하고자하는기관, 단체및사업자등은시장에게사용 승인신청서를제출하고, 위원회의심의를거쳐사용권에대한승인을받아야 한다. ③판매처표시를사용하는사용자가사회적으로민원을야기하거나공정무 역정신에위반된행위를할경우시장은위원회의심의를거쳐즉시사용승 인을취소할수있다. 제5장보칙'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제18조(준용)', '제18조(준용) 이조례에규정된사항외에공정무역단체의지원및관리등에 필요한사항은「광명시지방보조금관리조례」등예산·회계관계법령등을 준용한다.'),
  ('광명시 공정무역 지원 및 육성에 관한 조례', '제19조(시행규칙)', '제19조(시행규칙) 이조례의시행에필요한사항은규칙으로정한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제1조(목적)', '제1조(목적) 이조례는「사회적기업육성법」에따른사회적기업과예비사회적기업의 육성및지원을통하여사회서비스를확충하고, 새로운일자리를창출함으로써지역 사회의통합과주민의삶의질향상에기여함을목적으로한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의정의는다음과같다. 1. “사회적기업”이란「사회적기업육성법」(이하“법”이라한다) 제2조제1호의기업 을말한다. 2. “예비사회적기업”이란제1호의사회적기업으로인증받지는않았으나사회서비스 의제공, 취약계층에게일자리제공등사회적기업으로서의실체를갖추고장차 사회적기업으로의전환을준비하는기업을말한다. 3. “취약계층”이란법제2조제2호의계층을말한다. 4. “사회서비스”란법제2조제3호의서비스를말한다. 5. “연계기업”이란법제2조제4호의기업을말한다. 6. “사회적기업등”이란사회적기업및예비사회적기업을말한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제3조(사회적기업육성계획의수립)', '제3조(사회적기업육성계획의수립) ①광명시장(이하“시장”이라한다)은사회서비스 확충및일자리창출을위하여광명시사회적기업육성계획(이하“육성계획”이라한 다)을수립ㆍ시행하여야한다. ②제1항의육성계획에는다음각호의사항이포함되어야한다. 1. 사회적기업등의육성및지원을위한추진방향 2. 사회적기업등의활성화를위한여건조성에관한사항 3. 사회적기업등의운영지원에관한사항 4. 그밖에사회적기업등의육성및지원을위하여시장이필요하다고인정하는사항 ③시장은육성계획추진을위하여매년시행계획을수립ㆍ시행하되, 육성계획및 연도별시행계획기간이종료된후에는해당계획의성과등에대하여평가를실시 한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제4조(사회적기업육성위원회설치)', '제4조(사회적기업육성위원회설치) 시장은사회적기업등의육성및지원에관한다 음각호의사항을심의하기위하여광명시사회적기업육성위원회(이하“위원회”라 한다)를둔다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제5조(위원회기능)', '제5조(위원회기능) 위원회는다음각호의사항을심의한다. 1. 사회적기업등의육성계획및연도별시행계획의수립ㆍ평가에관한사항 2. 사회적기업등의운영과지원에관한사항 3. 예비사회적기업의운영과지원에관한사항 4. 그밖에사회적기업등의육성과지원을위하여시장이필요하다고인정하는사항'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제6조(위원회구성)', '제6조(위원회구성) ①위원회는위원장1명을포함한15명이내의위원으로구성하 되위원장은부시장이되며, 부위원장은위원중에서호선한다. ②위원은다음각호의사람중에서시장이임명또는위촉한다. 1. 당연직위원은광명시관계공무원으로한다. 2. 위촉직위원은광명시의회에서추천하는의원2명이내, 사회적기업등에대하여 학식과경험이풍부한사람, 시민단체및기업관계자등으로한다. ③위촉직위원의임기는2년으로한다. 다만, 공무원인위원의임기는해당직위에 재직하는기간으로한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제7조(위원장의직무)', '제7조(위원장의직무) ①위원장은위원회를대표하고, 위원회의직무를총괄한다. ②부위원장은위원장을보좌하며, 위원장이부득이한사유로직무를수행할수없 는경우에는그직무를대행한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제8조(회의)', '제8조(회의) ①위원장은위원회의회의를소집하고그의장이된다. ②위원회회의는재적위원과반수의출석으로회의를시작하고, 출석위원과반수의 찬성으로의결한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제9조(간사)', '제9조(간사) 위원회의사무를처리하기위하여위원회에간사1명을두되, 간사는사 회적기업육성업무를담당하는과장이된다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제10조(수당)', '제10조(수당) 위원회에출석한위원에게는예산의범위에서수당을지급할수있다. 다만, 시소속공무원인위원이그소관업무와관련하여출석하는경우에는그러하 지아니하다.〈개정2018. 7. 31〉'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제11조(위원의해촉)', '제11조(위원의해촉) 시장은위원이다음각호의어느하나에해당하는사유가발생 하였을때에는임기만료전이라도위원을해촉한다. 1. 위원본인이사직을원할때 2. 위원이사망, 질병그밖의사유로직무를수행하기어려운때 3. 위원이장기불참등으로직무수행이부적당하다고판단된때 4. 위원이위원회활동중에비리등부패에연루되었을때'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제12조(예비사회적기업의발굴및지원)', '제12조(예비사회적기업의발굴및지원) ①시장은예비사회적기업을사회적기업으로 육성하기위해노력하여야한다. ②시장은예비사회적기업설립및사회적기업전환을촉진하기위하여관계규정에 따라사회적기업으로인증받을수있도록행정적․재정적으로지원할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제13조(사회적기업등의발굴ㆍ지원)', '제13조(사회적기업등의발굴ㆍ지원) 시장은사회서비스를제공하거나취약계층에일 자리를제공하는법인또는단체등이사회적기업등으로설립ㆍ육성될수있도록 노력하여야한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제14조(경영지원등)', '제14조(경영지원등) ①시장은사회적기업등의설립과운영에필요한경영ㆍ법률ㆍ 기술ㆍ세무ㆍ노무ㆍ회계등의분야에대한전문적인자문및정보제공등각종지 원을할수있다. ②시장은제1항의지원업무를효율적으로추진하기위하여위원회의심의를거쳐 광명시출연기관이나민간단체에위탁할수있으며, 이경우에경비의전부또는일 부를예산의범위에서지원할수있다. ③시장은사회적기업등의설립ㆍ운영에필요한전문인력의육성, 사회적기업근로 자의능력향상을위하여교육훈련을실시할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제15조(사회적기업지원센터설치)', '제15조(사회적기업지원센터설치) ①시장은제14조에따라사회적기업등의설립과 운영에필요한지원업무를체계적이고종합적으로추진하기위하여사회적기업지 원센터(이하“지원센터”라한다)를설치ㆍ운영(위탁을포함한다)할수있다. ②제1항에따라지원센터의운영을위탁하는경우그위탁기간은3년이내로하며, 그기간을연장할수있다. ③제2항에따라위탁운영기간연장신청을할때에는운영기간만료60일전까지시 장에게신청하여야한다. ④시장은제3항에따라위탁운영기간연장신청을접수받은때에는위원회의심의를 거쳐위탁기간만료30일전까지신청인에게그결과를통지하여야한다. ⑤그밖에이조례에서정하지아니한지원센터의설치및운영에관한사항은시 장이정한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제16조(시설비등의지원)', '제16조(시설비등의지원) ①시장은사회적기업등의설립또는운영에필요한부지구 입비ㆍ시설비등을지원ㆍ융자하거나국․공유지를임대할수있다. ②시장은불용물품등을사회적기업등에무상양여할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제17조(재정지원)', '제17조(재정지원) ①시장은사회적기업등의자립을위하여필요하다고인정될때에 는예산의범위에서재정지원을할수있다. ②제1항의재정지원은지원계획을공고하고위원회에서심사를통하여결정한다. ③제1항의재정지원절차및구비서류, 사업실적보고, 지원의취소및환수절차등 은규칙으로정한다. ④제2항에의하여지원계획이결정된이후사업계획이변경되는경우에도시장의 승인을받아야하며, 국가또는기관․단체등으로부터신규또는추가로재정지원을 받을경우에는보조금을조정할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제17조의2(사회적기업의책무)', '제17조의2(사회적기업의책무) 광명시의행정적, 재정적지원을받은사회적기업은 지역사회에다양한방식으로균형발전과주민복지증진을위해노력하여야한다. 〔본조신설2025. 10. 2〕'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제18조(보고및검사등)', '제18조(보고및검사등) ①재정지원을교부받은사회적기업등은「광명시지방보 조금관리조례」및관련법령에따라실적보고서및정산서등을시장에게제출하 여야한다.〈개정2016. 9. 26〉 ②시장은지원금에대한적정한집행을기하기위하여필요하다고인정될때에는 교부받은사회적기업등에대하여소속공무원에게장부․서류또는그사업내용을 검사하게할수있다. ③시장은제2항에따라보고사항의검토및지도ㆍ 감독의결과필요한경우에는 시정을명령할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제19조(우선구매의촉진)', '제19조(우선구매의촉진) ①시장은사회적기업등이생산하는재화나서비스의우선 구매촉진을위하여노력하여야한다. ②시장은민간의소비장려등사회적기업등이생산하는재화나서비스의판로개 척을지원할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제20조(조세감면)', '제20조(조세감면) 시장은사회적기업등에대하여「지방세법」및「광명시시세감 면조례」가정하는바에따라시세를감면할수있다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제21조(연계사업)', '제21조(연계사업) ①시장은사회서비스확충및일자리창출사업을일반기업(연계 기업)과상호협약에의거공동으로추진할수있다. ②시장은다양하고많은기업이연계기업으로참여할수있도록적극노력하여야 한다. ③제1항의사회적기업에대하여는예산의범위에서행정적․재정적으로지원할수 있다.〈개정2018. 7. 31〉'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제22조(민간기업등의참여확충)', '제22조(민간기업등의참여확충) 시장은지역내민간기업ㆍ단체등이사회적기업 등의설립및육성에참여할수있도록다음각호에대하여노력하여야한다. 1. 지역내민간기업․단체간교류․협력네트워크의구축․운영지원 2. 연계기업의활성화를위한참여기업지원확대 3. 사회적기업등의설립및지원을위한기금등의설립'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제23조(홍보등)', '제23조(홍보등) 시장은사회적기업등에대한지역주민의이해증진을위하여다음 각호의조치를마련할수있다. 1. 지역내모범사회적기업모델발굴및확산지원 2. 지역내사회적기업등의제품및서비스품질제고및홍보지원 3. 전문가포럼, 워크숍개최, 사회적기업의날행사등을통한사회적기업등에대한 인식확산'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제24조(시행규칙)', '제24조(시행규칙) 이조례의시행에관하여필요한사항은규칙으로정한다.'),
  ('광명시 사회적기업 육성 및 지원에 관한 조례', '제1조(시행일)', '제1조(시행일) 이조례는공포한날부터시행한다. 제2조생략'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제1조(목적)', '제1조(목적) 이조례는「교육기본법」제4조및제10조, 「평생교육법」제5 조, 제7조, 제16조및제39조에따라, 민주주의가치실현을위한학습자중심 의문해교육을지향하며, 교육의기본원칙과광명시장의책무및재정적지원 등에필요한사항을정함을목적으로한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제2조(정의)', '제2조(정의) 이조례에서사용하는용어의뜻은다음과같다. 1. “문해교육(文解敎育)”이란일상생활에필요한능력을함양하지못하여비문 해자가된성인에대하여가정, 사회및직업생활에서적극적이고주체적인 삶을영위할수있도록이루어지는조직화된교육프로그램을말한다. 2. “문해교육기관등”이란문해교육을지속적으로제공하는평생교육시설과 그에준하는기관및비영리단체를말한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제3조(기본원칙)', '제3조(기본원칙) 문해교육지원과관련된기본원칙은다음과같다. 1. 문해교육은시민의삶의질향상과사회·문화적기초생활능력을보장하기 위한교육을지향한다. 2. 문해교육대상자에게는능력에따라균등하게교육을받을권리를보장한다. 3. 문해교육대상자의기본적인권을존중하고이를보장한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제4조(대상)', '제4조(대상) 문해교육은학령기동안빈곤, 건강, 성차별등의문제로인해교 육을받지못한문해능력이필요한성인을대상으로하되, 국적을불문한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제5조(시장의책무)', '제5조(시장의책무) 광명시장(이하“시장”이라한다)은문해교육의진흥을위하 여다음각호의사항에관한시책을마련하여야한다. 1. 문해교육대상자실태조사실시 2. 문해교육종합계획수립 3. 문해교육과정및교육내용의연구개발과보급지원 4. 문해교육기관등의지원및육성 5. 문해교육관련네트워크운영및지원 3750 - 2 6. 그밖의문해교육진흥에필요한사항'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제6조(사업의공동추진)', '제6조(사업의공동추진) 시장은문해교육사업의원활한추진을위하여광명교 육지원청및문해교육기관등과협력하여문해교육에필요한공동사업을적 극추진하여야한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제7조(공공시설의이용)', '제7조(공공시설의이용) 시장이문해교육기관등으로부터공공시설의이용요 청을받은때에는그본래의용도에지장이없는범위에서특별한사유가없 는한그이용을허용하여야한다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제8조(경비지원)', '제8조(경비지원) ①시장은문해교육프로그램을위하여「평생교육법」제39 조및같은법시행령제72조에따라문해교육기관등의사업에필요한경비 를예산의범위에서우선지원할수있다. ②시장은문해교육사업의예산편성에앞서광명교육지원청등문해교육 관계기관과협의할수있다. ③보조금의교부및관리에관한제반사항은「광명시지방보조금관리조 례」를따른다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제9조(교사연수등지원)', '제9조(교사연수등지원) 시장은문해교육교사의역량강화를위한연수와교 사조직의활성화사업을위하여필요한행정․재정적지원을할수있다.'),
  ('광명시 성인문해교육의 공공성 확보를 위한 조례', '제10조(시행규칙)', '제10조(시행규칙) 이조례의시행에필요한사항은규칙으로정한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제1조(목적)', '제1조(목적) 이 조례는 광명시 신중년층의 인생이모작 지원에 필요한 사항을 규정함 으로써 시민의 안정된 노후생활을 통한 사회안전망 구축을 목적으로 한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제2조(정의)', '제2조(정의) 이 조례에서 사용하는 용어의 뜻은 다음과 같다.〈개정 2023. 11. 10〉 1. “신중년층”이란 50세 이상 65세 미만인 사람을 말한다. 2. “인생이모작”이란 은퇴 전후에 새로운 인생을 준비하고 성공적인 노후생활을 위 한 모든 활동을 말한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제3조(시장의책무)', '제3조(시장의책무) 광명시장(이하 “시장”이라 한다)은 신중년층의 인생이모작 지원을 위하여 필요한 정책을 수립하여 시행하여야 한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제4조(지원대상)', '제4조(지원대상) ① 인생이모작 지원사업의 지원대상은 광명시에 주소를 두고 거주하 는 신중년층으로 한다. ② 시장이 필요하다고 인정하는 경우에는 지원대상을 신중년층 이외로 확대할 수 있 다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제5조(지원사업)', '제5조(지원사업) 시장은 신중년층의 인생이모작 지원을 위하여 다음 각 호에 해당하 는 사업을 추진 할 수 있다. 1. 교육관련 사업 2. 취업지원 및 일자리지원 사업 3. 창업 역량강화 및 협업교류지원 사업 4. 사회공헌활동 통합지원 사업 5. 건강증진 및 문화·여가지원 사업 6. 그 밖에 지원이 필요하다고 시장이 인정하는 사업'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제6조(인생이모작지원시설설치·운영)', '제6조(인생이모작지원시설설치·운영) ① 시장은 제5조의 지원 사업을 체계적으로 추 진하기 위하여 광명시 신중년층 인생이모작 지원시설(이하 “시설”이라 한다)을 설치· 운영할 수 있다.〈개정 2025. 7. 4〉 ② 제1항에 따른 광명시 신중년층 인생이모작 지원시설의 명칭은 “광명시인생플러스 센터”(이하 “센터”라 한다)로 한다.〈신설 2025. 7. 4〉'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제7조(시설의위탁)', '제7조(시설의위탁) ① 시장은 시설의 효율적인 관리·운영을 위하여 시설의 전부 또는 일부를 신중년층을 위한 인생이모작 교육 및 관련 사업을 추진하는 비영리법인 등에 위탁할 수 있다. ② 제1항에 따라 시설을 위탁하는 경우 위탁의 절차 및 방법 등 위탁에 필요한 사항 은 이 조례에 규정된 사항을 제외하고 「광명시 사무의 민간위탁 촉진 및 관리 조 례」를 준용한다. ③ 시장은 수탁기관에 위탁한 사업수행에 필요한 경비의 전부 또는 일부를 예산의 범위에서 지원할 수 있다. ④ 위탁받은 시설의 장은 매 회계연도마다 사업계획 및 예산서를 작성하여 시장에게 제출하여야 하며, 세입·세출 결산보고서는 다음 회계연도 1월 31일까지 시장에게 제 출하여야 한다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제8조(광명시인생이모작운영위원회설치)', '제8조(광명시인생이모작운영위원회설치) 시장은 다음 각 호의 사항을 자문하기 위 하여 광명시 인생이모작 운영위원회(이하 “위원회”라 한다)를 설치할 수 있다. 1. 신중년층 지원 시행계획의 수립에 관한 사항 2. 신중년층 지원 정책의 조정 및 평가에 관한 사항 3. 그 밖에 시장이 필요하다고 인정하는 사항 4. 위원회의 기능은 「광명시 일자리위원회 설치 및 운영에 관한 조례」에 따른 일 자리위원회에서 대행할 수 있다.'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제9조(수강신청)', '제9조(수강신청) 센터 교육과정을 수강하고자 하는 자는 별지 제1호서식에 따른 교육 수강 신청서를 시장에게 제출하여야 한다. 다만, 온라인으로 교육을 신청한 경우에는 신청서 제출을 생략한다. 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제10조(수강료징수)', '제10조(수강료징수) ① 시장은 센터 프로그램을 이용하는 수강생에게 수강료를 징수 할 수 있다. ② 수강료 및 수강료 면제 기준은 별표1에 따른다. 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제11조(수강료반환)', '제11조(수강료반환) ① 다음 각 호의 경우에는 즉시 반환 여부를 결정하고 이에 따 른 조치를 취하여야하며 수강료 반환 기준은 별표2에 따른다. 1. 센터의 사정으로 교육프로그램 진행이 불가능한 경우 2. 폐강이 결정되었을 때 3. 수강등록자가 본인의 의사로 수강을 포기한 경우 4. 그 밖에 시장이 필요하다고 인정하는 경우 ② 제1항에 따른 환불 사유의 경우 수강료 환불 신청서 별지 제2호 서식을 시장에게 제출하여야 한다. 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제12조(강사의위촉등)', '제12조(강사의위촉등) ① 교육 강사는 공개모집을 원칙으로 한다. 다만, 해당 분야 에 지원자가 없거나 교육의 특성상 필요하다고 인정할 경우에는 자격 또는 전문성이 있는 자를 지명하여 위촉할 수 있다. ② 위촉기간은 2년 이내로 한다. ③ 시장은 다음 각 호에 해당하는 강사를 해촉할 수 있다. 1. 업무 수행을 태만히 하여 교육에 중대한 지장을 초래한 자 2. 정당한 사유 없이 업무상 지시를 위반한 자 3. 강사로서의 품위를 손상한 자 4. 강의 관련 평가결과 기준점 이하의 경우 5. 수강생 모집 정원 미달로 폐강이 되는 경우 6. 센터의 사정으로 교육 프로그램을 개설ㆍ운영하지 못한 경우 〔본조신설 2025. 7. 4〕'),
  ('광명시 신중년층 인생이모작 지원에 관한 조례', '제13조(포상등)', '제13조(포상등) 시장은 센터 프로그램을 수료한 사람에게 수료증을 줄 수 있으며, 우수 수료자 및 공로가 인정되는 사람 및 단체 등에 대하여 「광명시 포상 조례」에 따라 포상할 수 있다. 〔본조신설 2025. 7. 4〕');

